label("$P$", p, N); label("$Q$", q, E); label("$R$", r, S); label("$S$", s, W);

// ARROWS
draw(shift(0.15,0.05)*a--shift(0.15,0.05)*p,Arrow);
draw(shift(0.15,-0.05)*b--shift(0.15,-0.05)*q,Arrow);
