label("$B$", B, NE);
label("$C$", C, SE);
label("$D$", D, SW);
dot("$G_A$", G[1], SE);
dot("$G_B$", G[2], W);
dot("$G_C$", G[3], NW);
dot("$G_D$", G[4], NE);
[/asy]

We can write
\begin{align*}
\mathbf{G_A} - \mathbf{G_B} &= \frac{\mathbf{b} + \mathbf{c} + \mathbf{d}}{3} - \frac{\mathbf{a} + \mathbf{c} + \mathbf{d}}{3} \\
&= \frac{\mathbf{b} - \mathbf{a}}{3} = \frac{\overrightarrow{AB}}{3},
\end{align*}and similarly,
\begin{align*}
\mathbf{G_B} - \mathbf{G_C} &= \frac{\overrightarrow{BC}}{3}, \\
\mathbf{G_C} - \mathbf{G_D} &= \frac{\overrightarrow{CD}}{3}, \\
\mathbf{G_D} - \mathbf{G_A} &= \frac{\overrightarrow{DA}}{3}.
\end{align*}Hence, the area of quadrilateral $G_A G_B G_C G_D$ is $\frac{1}{9}$ the area of quadrilateral $ABCD$.  Therefore, $\frac{[G_A G_B G_C G_D]}{[ABCD]} = \boxed{\frac{1}{9}}$.

