\begin{align*}
3333_4 &= 3 \cdot 4^3 + 3 \cdot 4^2 + 3 \cdot 4^1 + 3 \cdot 4^0 \\
&= 3 \cdot 64 + 3 \cdot 16 + 3 \cdot 4 + 3 \cdot 1 \\
&= \boxed{255}.
\end{align*}

